-- الدفعة الأولى من ملء محتوى تصنيفات "تعلّم" الفارغة (status='draft') تحت
-- "مصطلح الحديث" (mustalah-hadith) — تغطي 9 تصنيفات فرعية من أصل 11 (تصنيفان
-- منشوران سلفًا: الصحيح والحسن والضعيف، شروح الحديث): أقسام الحديث، المتواتر
-- والآحاد، أنواع الانقطاع، علل الرواية، الجرح والتعديل، طبقات الرواة، التحمل
-- والأداء، طرق التخريج، مناهج المحدثين وكتب السنة.
-- كل تصنيف يحصل على درس واحد (lessons + lesson_sections + lesson_citations)،
-- بنفس أسلوب الدرسين المنشورين سلفًا في هذا العنقود تحديدًا (تعريفي موجز: قسم
-- body/terms + قسم examples، مبني على مصادر مصطلح الحديث المعتمدة): نزهة
-- النظر شرح نخبة الفكر لابن حجر العسقلاني، تيسير مصطلح الحديث لمحمود الطحان،
-- علوم الحديث (مقدمة ابن الصلاح)، تقريب التهذيب لابن حجر، تدريب الراوي
-- للسيوطي.
-- حديثان أُشير إليهما بنصهما ضمن أمثلة التصنيف (لا كاستدلال ديني مستقل)،
-- تحقَّقا عبر WebSearch قبل الإدراج: "من كذب علي متعمدًا فليتبوأ مقعده من
-- النار" (متفق عليه، البخاري ومسلم، من أشهر الأمثلة على الحديث المتواتر)،
-- و"إنما الأعمال بالنيات" (رواه عمر بن الخطاب وحده عن النبي ﷺ، ثم تفرد به
-- علقمة بن وقاص ثم محمد بن إبراهيم التيمي ثم يحيى بن سعيد الأنصاري، من أشهر
-- الأمثلة على الحديث الغريب).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات التسعة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) أقسام الحديث باعتبار منتهاه
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='d00fb617-51a0-49d8-916f-6b35ab66c8b7' AND title='أقسام الحديث باعتبار منتهاه: المرفوع والموقوف والمقطوع') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أقسام الحديث باعتبار منتهاه: المرفوع والموقوف والمقطوع', 'تعريف موجز بتقسيم الحديث بحسب من أُضيف إليه: النبي ﷺ أو الصحابي أو التابعي', 'd00fb617-51a0-49d8-916f-6b35ab66c8b7', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'المرفوع والموقوف والمقطوع', 'المرفوع: ما أُضيف إلى النبي ﷺ من قول أو فعل أو تقرير أو صفة، سواء اتصل إسناده أو انقطع. الموقوف: ما أُضيف إلى الصحابي من قول أو فعل، ولم يُرفع إلى النبي ﷺ. المقطوع: ما أُضيف إلى التابعي أو من دونه من قول أو فعل، ويُفرَّق بينه وبين المنقطع (وهو وصف في الإسناد لا في المتن).', 1),
    (v_lesson, 'examples', 'مثال يوضح الفرق بين الرفع والوقف', 'إذا قال صحابي: ''من السنة كذا''، أعطى بعض المحدثين هذا القول حكم الرفع لأنه لا مجال للرأي فيه، بخلاف اجتهاده الشخصي في مسألة اختلف فيها الرأي، فإنه يبقى موقوفًا عليه لا يُرفع إلى النبي ﷺ.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'نزهة النظر شرح نخبة الفكر — الحافظ ابن حجر العسقلاني', 1);
  END IF;

  -- 2) المتواتر والآحاد
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='bf9bef57-f0d1-4d04-838d-a09af897810b' AND title='المتواتر والآحاد: تقسيم الحديث باعتبار عدد رواته') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('المتواتر والآحاد: تقسيم الحديث باعتبار عدد رواته', 'تعريف موجز بالحديث المتواتر وأقسام حديث الآحاد الثلاثة: المشهور والعزيز والغريب', 'bf9bef57-f0d1-4d04-838d-a09af897810b', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'المتواتر والآحاد وأقسامه', 'المتواتر: ما رواه جمع كثير يستحيل عادة تواطؤهم على الكذب، عن مثلهم، في كل طبقات السند، مستندين إلى حس. والآحاد: ما لم يبلغ حد التواتر، وينقسم إلى: المشهور (رواه ثلاثة فأكثر في كل طبقة دون بلوغ التواتر)، والعزيز (رواه اثنان على الأقل في طبقة من طبقات السند)، والغريب (تفرد بروايته راوٍ واحد في أي موضع من مواضع السند).', 1),
    (v_lesson, 'examples', 'مثالان من أشهر أمثلة المحدثين', 'من أشهر الأمثلة على المتواتر عند المحدثين حديث ''من كذب عليَّ متعمدًا فليتبوأ مقعده من النار'' (متفق عليه)، لكثرة من رواه من الصحابة. ومن أشهر الأمثلة على الغريب حديث ''إنما الأعمال بالنيات''، إذ تفرد عمر بن الخطاب برواية أصله عن النبي ﷺ، ثم تفرد عنه علقمة بن وقاص، ثم محمد بن إبراهيم التيمي، ثم يحيى بن سعيد الأنصاري، قبل أن ينتشر عنه فيرويه عدد كبير من الرواة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'تيسير مصطلح الحديث — محمود الطحان', 1);
  END IF;

  -- 3) أنواع الانقطاع
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='a99032a8-7e91-43cf-a58a-cdb799d51e87' AND title='أنواع الانقطاع في السند: المرسل والمنقطع والمعضل والمعلّق') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أنواع الانقطاع في السند: المرسل والمنقطع والمعضل والمعلّق', 'تعريف موجز بأنواع السقط في سند الحديث بحسب موضعه وعدد رواته الساقطين', 'a99032a8-7e91-43cf-a58a-cdb799d51e87', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'أنواع السقط في الإسناد', 'المرسل: ما سقط منه الصحابي، فرواه التابعي مباشرة عن النبي ﷺ. المنقطع: ما سقط من إسناده راوٍ واحد أو أكثر في موضع واحد غير الصحابي، من غير توالٍ. المعضل: ما سقط من إسناده راويان فأكثر على التوالي. المعلّق: ما حُذف من مبدأ إسناده راوٍ واحد فأكثر على التوالي، كأن يقول المصنف: قال رسول الله ﷺ، دون ذكر سلسلة رواته إليه.', 1),
    (v_lesson, 'examples', 'مثال يوضح الفرق بين الأنواع', 'إذا روى تابعي حديثًا فقال ''قال رسول الله ﷺ'' دون ذكر الصحابي الذي سمعه منه، فهذا مرسل؛ وإذا حُذف راويان متتاليان من وسط السند فهو معضل؛ أما إذا بدأ المصنف إسناده مباشرة بشيخه دون ذكر من فوقه فهو معلَّق.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'نزهة النظر شرح نخبة الفكر — الحافظ ابن حجر العسقلاني', 1);
  END IF;

  -- 4) علل الرواية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='0b0e5c5a-b3f2-4eea-be9a-d006781aa3e8' AND title='علل الرواية: تعريف الحديث المعلول وطريق الكشف عنه') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('علل الرواية: تعريف الحديث المعلول وطريق الكشف عنه', 'تعريف موجز لعلم علل الحديث وأثره في الحكم على صحة الأسانيد', '0b0e5c5a-b3f2-4eea-be9a-d006781aa3e8', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'تعريف العلة وطريق الكشف عنها', 'علة الحديث سبب خفي غامض قادح في صحته، مع أن ظاهر إسناده السلامة منه. ويُتوصَّل إلى معرفة الحديث المعلول بجمع طرقه كلها والنظر في اختلاف الرواة فيه، كأن يتبين أن الموصول في الحقيقة مرسل، أو المرفوع موقوف، أو يقع وهم في اسم راوٍ فيُظن ثقة وهو غيره. من أشهر من صنّف في هذا الفن الدقيق الإمام علي بن المديني والإمام الدارقطني في كتابه ''العلل''.', 1),
    (v_lesson, 'examples', 'مثال على كيفية الحكم بالعلة', 'قد يروي الحديث جماعة من الحفاظ موقوفًا على صحابي، وينفرد راوٍ واحد برفعه إلى النبي ﷺ؛ فإذا كان هذا الراوي المخالف أضعف ضبطًا أو أقل عددًا من الجماعة الذين وقفوه، حكم الحفاظ بأن الرفع علة قادحة في الحديث.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'علوم الحديث (مقدمة ابن الصلاح) — الإمام ابن الصلاح الشهرزوري', 1);
  END IF;

  -- 5) الجرح والتعديل
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='0148711f-a1cf-4d86-bd36-6873d0d7cbfe' AND title='الجرح والتعديل: قواعده وصيغه المتدرجة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الجرح والتعديل: قواعده وصيغه المتدرجة', 'تعريف موجز بعلم الجرح والتعديل وأبرز قواعده في الموازنة بين أقوال النقاد', '0148711f-a1cf-4d86-bd36-6873d0d7cbfe', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'الجرح والتعديل وقاعدتهما', 'الجرح: وصف الراوي بما يقتضي ضعفه أو سقوط روايته، لطعن في عدالته أو ضبطه. التعديل: وصفه بما يقتضي قبول روايته، من عدالة وضبط. وقد وضع النقاد ألفاظًا متدرجة لكل منهما، من أعلى مراتب التعديل (كـ''ثقة ثقة'') إلى أدنى مراتب الجرح (كـ''متروك الحديث'' و''كذّاب'')، وقاعدتهم المشهورة أن الجرح المفسَّر (المذكور سببه) مقدَّم على التعديل عند التعارض.', 1),
    (v_lesson, 'examples', 'مثال على تطبيق قاعدة تقديم الجرح المفسَّر', 'إذا قال إمام: ''فلان ثقة''، وقال آخر: ''فلان ضعيف يروي المناكير''، رجَّح المحدثون قول الجارح المفسِّر لسبب جرحه، لأنه اطَّلع على ما لم يطَّلع عليه المعدِّل الذي اكتفى بحكم مجمل.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'تيسير مصطلح الحديث — محمود الطحان', 1);
  END IF;

  -- 6) طبقات الرواة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='1ffb3fa4-d9d9-4186-97d8-55b7dd9cc4f5' AND title='طبقات الرواة: تقسيم رواة الحديث زمنيًا') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('طبقات الرواة: تقسيم رواة الحديث زمنيًا', 'تعريف موجز بمفهوم طبقة الراوي وأشهر تقسيمات المحدثين لطبقات الرواة', '1ffb3fa4-d9d9-4186-97d8-55b7dd9cc4f5', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'تعريف الطبقة وأصنافها العامة', 'طبقة الراوي جماعة تشاركوا في السن ولقاء المشايخ غالبًا. وأشهر تقسيم عام للرواة: الصحابة (من لقي النبي ﷺ مؤمنًا به ومات على ذلك)، ثم التابعون (من لقي صحابيًا كذلك)، ثم أتباع التابعين، ثم من بعدهم من طبقات المتأخرين. وقد فصَّل العلماء الصحابة والتابعين إلى طبقات فرعية بحسب السابقة في الإسلام أو الهجرة أو السن، كما فعل ابن سعد في ''الطبقات الكبرى''.', 1),
    (v_lesson, 'examples', 'مثال من تقسيم ابن حجر لطبقات رواة الكتب الستة', 'قسَّم الحافظ ابن حجر العسقلاني في ''تقريب التهذيب'' رواة الكتب الستة إلى اثنتي عشرة طبقة، أولاها طبقة الصحابة، تنازلاً حتى الطبقة الثانية عشرة من صغار أتباع التابعين ممن أدرك بعض كبار أتباع أتباع التابعين.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'تقريب التهذيب — الحافظ ابن حجر العسقلاني', 1);
  END IF;

  -- 7) التحمل والأداء
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='8d85c6e0-84a5-41be-ac56-d8f47ed8b09c' AND title='التحمل والأداء: طرق تلقي الحديث وروايته الثماني') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('التحمل والأداء: طرق تلقي الحديث وروايته الثماني', 'تعريف موجز بطرق تحمل الحديث الثماني عند المحدثين من السماع إلى الوجادة', '8d85c6e0-84a5-41be-ac56-d8f47ed8b09c', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'طرق التحمل الثماني مرتبة', 'طرق تحمل الحديث ثماني عند المحدثين، أعلاها السماع من لفظ الشيخ، ثم القراءة على الشيخ (العرض)، ثم الإجازة (أن يأذن الشيخ لطالبه برواية مروياته دون قراءة أو سماع)، ثم المناولة (أن يعطي الشيخ طالبه أصل سماعه أو نسخة منه)، ثم الكتابة (أن يكتب الشيخ الحديث لطالبه بخطه)، ثم الإعلام (إعلام الشيخ طالبه بأن هذا الحديث من مسموعاته دون إذن صريح بالرواية)، ثم الوصية (أن يوصي الشيخ عند سفره أو موته بكتاب من مروياته لمعيَّن)، وآخرها الوجادة (أن يجد الطالب أحاديث بخط راويها دون سماع أو إجازة).', 1),
    (v_lesson, 'examples', 'مثال على صيغ الأداء الدالة على طريقة التحمل', 'إذا قال الراوي ''أخبرنا فلان قراءة عليه'' دلَّ ذلك على أن تحمله كان بطريق العرض على الشيخ لا بالسماع من لفظه؛ وإذا قال ''أنبأنا فلان إجازة'' دلَّ على أن تحمله كان بالإجازة لا بسماع أو قراءة مباشرة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'تيسير مصطلح الحديث — محمود الطحان', 1);
  END IF;

  -- 8) طرق التخريج
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='7fa95b12-764b-4e39-b182-39b68bae844f' AND title='طرق التخريج: كيفية الوصول إلى مصادر الحديث الأصلية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('طرق التخريج: كيفية الوصول إلى مصادر الحديث الأصلية', 'تعريف موجز بطرق تخريج الحديث الأربع وأشهر الكتب المعينة على كل طريق', '7fa95b12-764b-4e39-b182-39b68bae844f', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'معنى التخريج وطرقه', 'التخريج هو الدلالة على مواضع الحديث في مصادره الأصلية مع بيان درجته عند الحاجة. وله عدة طرق: التخريج عن طريق الراوي الأعلى (الصحابي) باستخدام كتب الأطراف والمسانيد المرتبة على الصحابة كمسند الإمام أحمد؛ والتخريج عن طريق أول لفظ الحديث باستخدام المعاجم المرتبة على الحروف الهجائية؛ والتخريج عن طريق موضوع الحديث باستخدام الكتب المرتبة على الأبواب الفقهية؛ والتخريج عن طريق صفة ظاهرة في السند أو المتن.', 1),
    (v_lesson, 'examples', 'مثال على استخدام معجم الألفاظ في التخريج', 'للبحث عن حديث معروف اللفظ مجهول مصدره، يلجأ الباحث إلى ''المعجم المفهرس لألفاظ الحديث النبوي'' فيبحث عن كلمة مميزة في متن الحديث ليجد إحالات إلى مواضعه في الكتب التسعة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'تدريب الراوي شرح تقريب النواوي — الإمام جلال الدين السيوطي', 1);
  END IF;

  -- 9) مناهج المحدثين وكتب السنة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='c0d0902f-85c9-4ccc-a400-98ea5f809a9b' AND title='مناهج المحدثين وكتب السنة: الصحاح والسنن والمسانيد') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('مناهج المحدثين وكتب السنة: الصحاح والسنن والمسانيد', 'تعريف موجز بأبرز أنواع مصنفات الحديث ومناهج مصنفيها', 'c0d0902f-85c9-4ccc-a400-98ea5f809a9b', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'أنواع مصنفات السنة ومناهجها', 'تنوعت مصنفات السنة بحسب منهج مصنفيها: فمنها الصحاح، كصحيح البخاري وصحيح مسلم، والتزم أصحابها جمع الأحاديث الصحيحة فقط دون التزام استيعاب كل صحيح؛ ومنها السنن، كسنن أبي داود والترمذي والنسائي وابن ماجه، وهي مرتبة على الأبواب الفقهية وتضم الصحيح وغيره مع بيان درجة بعض أحاديثها أحيانًا؛ ومنها المسانيد، كمسند الإمام أحمد بن حنبل، وهي مرتبة على أسماء الصحابة رواة الحديث لا على الأبواب الفقهية؛ ومنها المصنَّفات والجوامع التي تضم أبوابًا متعددة كالعقائد والأحكام والآداب.', 1),
    (v_lesson, 'examples', 'مثال على الفرق بين الصحيحين وأصحاب السنن', 'يشترك البخاري ومسلم في وصف ''الصحيح'' لالتزامهما جمع الأحاديث الصحيحة فقط وفق شرطيهما، بخلاف أصحاب السنن الأربعة الذين أدخلوا في كتبهم الحديث الضعيف أحيانًا مع التنبيه على درجته.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'علوم الحديث (مقدمة ابن الصلاح) — الإمام ابن الصلاح الشهرزوري', 1);
  END IF;

